const parseSize = (s) => {
  if (!s) return { w: 18, h: 12 };
  const m = s.match(/(\d+)\s*[xX×]\s*(\d+)/);
  if (!m) return { w: 18, h: 12 };
  return { w: parseInt(m[1]), h: parseInt(m[2]) };
};
