/* ============ HELPER COMPONENTS ============ */

const HospitalBadge = ({ hospital, compact = false }) => (
  <div className="inline-flex items-center gap-2 rounded-xl px-2 py-1 bg-white" style={{ border: `1.5px solid ${hospital.primaryColor}` }}>
    <div className="rounded-md bg-white flex items-center justify-center overflow-hidden flex-shrink-0" style={{ width: compact ? 26 : 32, height: compact ? 26 : 32 }}>
      {hospital.logoDataUrl
        ? <img src={hospital.logoDataUrl} className="w-full h-full object-contain" alt="logo" />
        : <Shield size={compact ? 18 : 22} style={{ color: hospital.primaryColor }} fill={hospital.accentColor} strokeWidth={2.5} />}
    </div>
    <div className="leading-tight">
      <div className="font-black uppercase tracking-tight" style={{ color: hospital.primaryColor, fontSize: compact ? '0.72rem' : '0.82rem', fontFamily: 'Georgia, serif' }}>
        {hospital.name.split(' ')[0]}
      </div>
      <div className="font-bold text-slate-500" style={{ fontSize: '1rem' }}>
        {hospital.name.split(' ').slice(1, 4).join(' ')}
      </div>
    </div>
  </div>
);

// THE signature pattern: teal pill bulges into blue field
const CurvedStrip = ({ icon: Icon, accentText, primaryText, hindiText, trailingNumber, primary, accent, height = 70 }) => {
  const iconSz = height * 0.42;
  const leftWidth = height * 1.4;
  return (
    <div className="relative w-full rounded-xl overflow-hidden shadow-sm flex items-stretch" style={{ background: primary, height }}>
      <div className="absolute top-0 bottom-0 left-0 flex items-center justify-center"
           style={{ background: accent, width: leftWidth, borderTopRightRadius: 999, borderBottomRightRadius: 999, zIndex: 2 }}>
        {Icon ? <Icon size={iconSz} className="text-white -ml-2" strokeWidth={2} />
              : accentText ? <span className="font-black text-white leading-none" style={{ fontSize: height * 0.55, fontFamily: 'Georgia, serif' }}>{accentText}</span>
              : null}
      </div>
      <div className="flex-1 flex items-center text-white relative z-10 justify-between" style={{ paddingLeft: leftWidth + 14, paddingRight: 16 }}>
        <div className="flex-1 leading-tight min-w-0">
          {primaryText && <div className="font-bold tracking-tight truncate" style={{ fontSize: height * 0.28 }}>{primaryText}</div>}
          {hindiText && <div className="font-medium opacity-95 truncate" style={{ fontSize: height * 0.22 }}>{hindiText}</div>}
        </div>
        {trailingNumber !== undefined && (
          <div className="font-black leading-none ml-3 flex-shrink-0" style={{ fontSize: height * 0.6, fontFamily: 'Georgia, serif' }}>{trailingNumber}</div>
        )}
      </div>
    </div>
  );
};

