const BilingualTitle = ({ en, hi, primary, size = 'lg' }) => {
  // R7du-Content — Sizes bumped (Hindi was 0.65–0.8rem, too cramped) and
  // explicit line-height added so Devanagari diacritics don't clip / overlap
  // the next line. Was 'leading-tight' (1.25) which lost top matras.
  const sizes = { sm: ['1.15rem', '0.92rem'], md: ['1.35rem', '1rem'], lg: ['1.55rem', '1.12rem'] };
  return (
    <div className="text-center">
      <h1 className="font-black uppercase tracking-tight" style={{ color: primary, fontSize: sizes[size][0], fontFamily: 'Georgia, serif', lineHeight: 1.2 }}>{en}</h1>
      {hi && <div className="font-medium" style={{ color: primary, fontSize: sizes[size][1], lineHeight: 1.45, marginTop: 2 }}>{hi}</div>}
    </div>
  );
};

