/* ---------- PRINT MARKS COMPONENT (bleed + crop marks) ---------- */
const PrintMarks = ({ children, widthMm, heightMm, bleedMm = 3, cropLen = 4, scale = 1 }) => {
  // scale: px per mm for screen preview. For actual print, use 1mm = 1mm.
  const totalW = (widthMm + bleedMm * 2) * scale;
  const totalH = (heightMm + bleedMm * 2) * scale;
  const inset = bleedMm * scale;
  const cropL = cropLen * scale;
  const cropOffset = 0.5 * scale;
  return (
    <div className="relative inline-block" style={{ width: totalW, height: totalH, background: '#fff' }}>
      {/* Inner content area (trim size + bleed) */}
      <div className="absolute" style={{ left: inset, top: inset, width: widthMm * scale, height: heightMm * scale }}>
        {children}
      </div>
      {/* Bleed boundary (dashed) */}
      <div className="absolute pointer-events-none border border-dashed" style={{
        left: inset, top: inset, width: widthMm * scale, height: heightMm * scale,
        borderColor: 'rgba(220,38,38,0.45)',
      }} />
      {/* Crop marks (8 lines, 2 per corner) */}
      <svg className="absolute inset-0 pointer-events-none" width={totalW} height={totalH}>
        {[
          // Top-left
          [0, inset, cropL - cropOffset, inset], [inset, 0, inset, cropL - cropOffset],
          // Top-right
          [totalW - cropL + cropOffset, inset, totalW, inset], [totalW - inset, 0, totalW - inset, cropL - cropOffset],
          // Bottom-left
          [0, totalH - inset, cropL - cropOffset, totalH - inset], [inset, totalH - cropL + cropOffset, inset, totalH],
          // Bottom-right
          [totalW - cropL + cropOffset, totalH - inset, totalW, totalH - inset], [totalW - inset, totalH - cropL + cropOffset, totalW - inset, totalH],
        ].map(([x1, y1, x2, y2], i) => (
          <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke="#0F172A" strokeWidth={1} />
        ))}
      </svg>
      {/* Dimension labels */}
      <div className="absolute -top-5 left-0 right-0 text-center font-mono text-slate-500" style={{ fontSize: 10 }}>
        ↔ {widthMm} mm
      </div>
      <div className="absolute top-0 -left-12 bottom-0 flex items-center justify-end pr-1 font-mono text-slate-500" style={{ fontSize: 10, transform: 'rotate(-90deg)', transformOrigin: 'right center', width: 80, right: 'auto' }}>
        ↕ {heightMm} mm
      </div>
    </div>
  );
};

